'use strict';
// Simulate what the browser does with the JSON
const json = JSON.stringify({extends: 'zombie.iso.IsoMovingObject', implements: ['foo'], subclasses: ['bar']});
const cls = JSON.parse(json);
console.log('cls.extends:', cls.extends);
console.log('cls[\"extends\"]:', cls['extends']);
console.log('both equal:', cls.extends === cls['extends']);
const hasExtends = !!cls.extends;
console.log('hasExtends:', hasExtends);
// Optional chaining
const API = {classes: {}};
API.classes['test'] = cls;
console.log('optional chain:', API.classes['test']?.extends);
")
